var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하아, 하…… 숨 차……","JPN":"はあ、は……きつい。","ENG":"*Huff...* *Huff...* I need to catch my breath...","TWN":"呼呼，呼…好累…"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도 이제 더 달려들지는 않는 건가?","JPN":"でも、もう飛びかかってこないのね。","ENG":"But it seems like they've stopped chasing after us.","TWN":"他們好像沒有再撲過來？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇다면 여기가 기관실인 것 같은데…….","JPN":"だとすると、ここが機関室ってことだけど……","ENG":"That'll mean that this is the engine room...","TWN":"這麼說來，這裡應該就是駕駛室……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뭔가 생각했던 분위기와는 많이 다른걸.","JPN":"なんだか、思ってた雰囲気とはだいぶ違うな。","ENG":"It's a lot different from what I imagined it to be.","TWN":"和我想像中的感覺截然不同呢。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"그럴 수밖에요.","JPN":"そうでしょう。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 곳은 제가 교단에 몸 담기 전 지냈던 시설이랍니다.","JPN":"ここは、私が教団に所属する前に暮らしていた施設です。","ENG":"This is the facility where I was before I joined the church.","TWN":"這裡是我加入教團之前住過的地方。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"보이지 않아도 알 수 있을 만큼, 무척이나 삭막한 공간이었지요.","JPN":"見えなくてもわかるほど、とても殺風景な空間でした。","ENG":"Although I could not see, I could tell how dreary of a place it was.","TWN":"我雖然看不見，但依然能感受到這裡的淒涼。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로…….","JPN":"マエストロ……","ENG":"Maestra...","TWN":"指揮家……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"매주마다, 미사를 치르는 날에는 고기 타는 악취가 시설을 맴돌았지요.","JPN":"毎週、ミサの日には肉が焦げる悪臭が施設を漂っていました。","ENG":"Every week, when mass was held, this place would stink of burning meat.","TWN":"每週舉行彌撒聖祭時，這裡都會充斥著皮肉燒焦的惡臭。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"교리를 가르치러 온 사제들은 이교도들의 영혼을 정화하면서 나온 나쁜 마음 탓이라고 하였지만….","JPN":"教理を教えに来た司祭は、異教徒の魂を浄化していく中で出る、悪い心のせいであると言っていましたが……","ENG":"The priests who came to teach us the doctrine told us that it was the smell of malice that was extracted as the heretics' souls were purified, but I knew the truth...","TWN":"來傳授教義的祭司們說，那是淨化異教徒們的靈魂時，散發出的惡念之氣，但是……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저는 태어날 때부터 앞이 보이지 않는 대신에 남들보다 귀가 밝았습니다.","JPN":"私は生まれた時から目が見えない代わりに、人より耳が良かったのです。","ENG":"Although I was blind from birth, I had good hearing.","TWN":"我雖天生眼盲，但從小就有著超乎常人的聽力。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"사제들의 부름을 받고 간 우리의 친구와 부모들이 강철 문을 손톱으로 긁어대던 소음.","JPN":"司祭に呼ばれて出て行った友だちとその親が、鋼鉄のドアを爪で引っ掻く騒音。","ENG":"The sound of my friends and their parents who were called in by the priests clawing against the iron door.","TWN":"被祭司們叫去的朋友，和他們的父母用指甲拼命抓鐵門發出的噪音，"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"살과 뼈가 타들어가는 소음.","JPN":"肉と骨が燃えてゆく騒音。","ENG":"The crackling sound of scorching flesh and bone.","TWN":"皮肉筋骨被燒焦的噪音，"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그리고 자신들의 순번이 아직 오지 않았다고 외면하는 이들의 심장 박동까지.","JPN":"そして、まだ自分たちの順番ではないと現実に目を背ける者たちの心臓の音まで。","ENG":"And the pounding sound of hearts from those who turned a blind eye because their turn had not yet come.","TWN":"還有那些害怕輪到自己的人，他們的心跳聲，"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"모두 듣고 있었지요.","JPN":"全部聞いていたのです。","ENG":"I heard it all.","TWN":"我都聽得非常清楚。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"환영합니다. 그리고 반갑습니다.","JPN":"ようこそ、お会いできて嬉しいです。","ENG":"Welcome. A pleasure to meet you.","TWN":"歡迎，很高興見到你。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}}]`);export{e as default};